'use client';

import { useState, useEffect, useRef } from 'react';
import Image from 'next/image';

export default function HomePage() {
  const [activeLink, setActiveLink] = useState('discover');
  const [isMainContainerShow, setIsMainContainerShow] = useState(false);
  const [currentVideo, setCurrentVideo] = useState(null);
  const videoRefs = useRef({});

  useEffect(() => {
    // Handle responsive sidebar
    const handleResize = () => {
      const sidebar = document.querySelector('.sidebar');
      if (window.innerWidth > 1090) {
        sidebar.classList.remove('collapse');
      } else {
        sidebar.classList.add('collapse');
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial call

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleSidebarLinkClick = (link) => {
    setActiveLink(link);
    if (link === 'discover') {
      setIsMainContainerShow(false);
    }
  };

  const handleVideoHover = (videoId, action) => {
    const videoElement = videoRefs.current[videoId];
    if (videoElement) {
      action === 'play' ? videoElement.play() : videoElement.pause();
    }
  };

  const handleVideoClick = (video) => {
    setCurrentVideo(video);
    setIsMainContainerShow(true);
    setActiveLink('trending');
  };

  return (
    <div className="container">
      <div className="sidebar">
        <span className="logo">S</span>
        <a className="logo-expand" href="#">skateboard</a>
        <div className="side-wrapper">
          <div className="side-title">MENU</div>
          <div className="side-menu">
            {['discover', 'trending', 'streaming', 'playlist', 'bookmark'].map(link => (
              <a 
                key={link}
                href="#" 
                className={`sidebar-link ${link} ${activeLink === link ? 'is-active' : ''}`}
                onClick={() => handleSidebarLinkClick(link)}
              >
                {/* SVG icons would be added here */}
                {link.charAt(0).toUpperCase() + link.slice(1)}
              </a>
            ))}
          </div>
        </div>
        {/* Rest of the sidebar content */}
      </div>
      <div className={`wrapper ${isMainContainerShow ? 'show' : ''}`}>
        {/* Main content similar to original HTML */}
        <div className="videos">
          {[
            {
              id: 1,
              time: '8 min',
              videoSrc: 'https://player.vimeo.com/external/436572488.sd.mp4?s=eae5fb490e214deb9ff532dd98d101efe94e7a8b&profile_id=139&oauth2_token_id=57447761',
              authorImg: 'https://images.pexels.com/photos/1680172/pexels-photo-1680172.jpeg?auto=compress&cs=tinysrgb&dpr=2&w=500',
              videoBy: 'Andy William',
              videoName: 'Basic how to ride your skateboard comfortably'
            },
            // Add more video objects
          ].map(video => (
            <div 
              key={video.id} 
              className="video" 
              onMouseEnter={() => handleVideoHover(video.id, 'play')}
              onMouseLeave={() => handleVideoHover(video.id, 'pause')}
              onClick={() => handleVideoClick(video)}
            >
              <div className="video-time">{video.time}</div>
              <div className="video-wrapper">
                <video 
                  ref={el => videoRefs.current[video.id] = el} 
                  muted 
                  src={video.videoSrc}
                />
                <div className="author-img__wrapper video-author">
                  <Image 
                    src={video.authorImg} 
                    alt={video.videoBy} 
                    width={50} 
                    height={50} 
                    className="author-img" 
                  />
                </div>
              </div>
              <div className="video-by">{video.videoBy}</div>
              <div className="video-name">{video.videoName}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
